using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void SetUp() => _cart = new ShoppingCart();

    // ───────────────────────── AddItem ─────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.IsTrue(_cart.Items.ContainsKey("SKU-1"));
        Assert.AreEqual(2, _cart.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllAppearInCart()
    {
        _cart.AddItem("A", 1, 5.00m);
        _cart.AddItem("B", 3, 12.50m);

        Assert.AreEqual(2, _cart.Items.Count);
    }

    [TestMethod]
    public void AddItem_DuplicateSku_QuantitiesAccumulate()
    {
        _cart.AddItem("SKU-1", 2, 10.00m);
        _cart.AddItem("SKU-1", 3, 10.00m);

        Assert.AreEqual(5, _cart.Items["SKU-1"].Quantity);
    }

    [TestMethod]
    public void AddItem_DuplicateSku_PriceIsUpdatedToLatest()
    {
        _cart.AddItem("SKU-1", 1, 10.00m);
        _cart.AddItem("SKU-1", 1, 15.00m);

        Assert.AreEqual(15.00m, _cart.Items["SKU-1"].Price);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_NullOrWhiteSpaceSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem(sku!, 1, 5.00m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_ZeroOrNegativeQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU-1", quantity, 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU-1", 1, -1.00m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _cart.AddItem("FREE", 1, 0.00m);

        Assert.AreEqual(0.00m, _cart.Items["FREE"].Price);
    }

    // ───────────────────────── RemoveItem ─────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovedFromCart()
    {
        _cart.AddItem("SKU-1", 1, 10.00m);
        _cart.RemoveItem("SKU-1");

        Assert.AreEqual(0, _cart.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void RemoveItem_NullOrWhiteSpaceSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem(sku!));
    }

    [TestMethod]
    public void RemoveItem_OnlyTargetItem_OtherItemsRemain()
    {
        _cart.AddItem("A", 1, 5.00m);
        _cart.AddItem("B", 1, 7.00m);
        _cart.RemoveItem("A");

        Assert.IsFalse(_cart.Items.ContainsKey("A"));
        Assert.IsTrue(_cart.Items.ContainsKey("B"));
    }

    // ───────────────────────── CalculateTotal ─────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-1", 3, 4.50m);

        Assert.AreEqual(13.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _cart.AddItem("A", 2, 10.00m);
        _cart.AddItem("B", 1, 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemovedItem()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 20.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ───────────────────────── ApplyCoupon ─────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_SetsAppliedCoupon()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual("SAVE10", _cart.AppliedCoupon);
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ApplyCoupon_NullOrWhiteSpace_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_IsAccepted()
    {
        _cart.ApplyCoupon("save10");

        Assert.IsNotNull(_cart.AppliedCoupon);
    }

    [TestMethod]
    public void ApplyCoupon_CalledTwice_SecondCouponReplaceFirst()
    {
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual("SAVE20", _cart.AppliedCoupon);
    }

    // ───────────────── CalculateTotal + Coupon ─────────────────

    [TestMethod]
    public void CalculateTotal_WithSave10_Applies10PercentDiscount()
    {
        _cart.AddItem("A", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_WithSave20_Applies20PercentDiscount()
    {
        _cart.AddItem("A", 1, 50.00m);
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_WithHalf_Applies50PercentDiscount()
    {
        _cart.AddItem("A", 2, 30.00m);
        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_CouponOnEmptyCart_ReturnsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_DiscountRoundsToTwoDecimals()
    {
        _cart.AddItem("A", 1, 9.99m);
        _cart.ApplyCoupon("SAVE10");

        // 9.99 * 0.90 = 8.991 → rounds to 8.99
        Assert.AreEqual(8.99m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_NoCoupon_NoDiscount()
    {
        _cart.AddItem("A", 1, 100.00m);

        Assert.IsNull(_cart.AppliedCoupon);
        Assert.AreEqual(100.00m, _cart.CalculateTotal());
    }
}

